// tests/integration/ready_tests.rs
#[test]
fn test_ready_empty() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .success()
        .stdout(predicate::str::contains("No issues ready").or(predicate::str::contains("0")));
}

#[test]
fn test_ready_basic() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    create_issue(&beads_dir, "Ready issue 1");
    create_issue(&beads_dir, "Ready issue 2");

    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .success()
        .stdout(predicate::str::contains("Ready issue 1"))
        .stdout(predicate::str::contains("Ready issue 2"));
}

#[test]
fn test_ready_excludes_closed() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    let id = create_issue(&beads_dir, "Closed issue");
    br_cmd(&beads_dir)
        .args(["close", &id])
        .assert()
        .success();

    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .success()
        .stdout(predicate::str::contains("Closed issue").not());
}

#[test]
fn test_ready_excludes_blocked() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    let blocker = create_issue(&beads_dir, "Blocker");
    let blocked = create_issue(&beads_dir, "Blocked issue");

    br_cmd(&beads_dir)
        .args(["dep", "add", &blocked, &blocker])
        .assert()
        .success();

    // Ready should show blocker but not blocked
    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .success()
        .stdout(predicate::str::contains("Blocker"))
        .stdout(predicate::str::contains("Blocked issue").not());
}

