#[test]
fn test_ready_sort_priority() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    br_cmd(&beads_dir)
        .args(["create", "P3 issue", "--priority", "3"])
        .assert()
        .success();
    br_cmd(&beads_dir)
        .args(["create", "P0 issue", "--priority", "0"])
        .assert()
        .success();
    br_cmd(&beads_dir)
        .args(["create", "P1 issue", "--priority", "1"])
        .assert()
        .success();

    let output = br_cmd(&beads_dir)
        .args(["ready", "--sort", "priority", "--json"])
        .output()
        .unwrap();

    let json: Value = serde_json::from_slice(&output.stdout).unwrap();
    let issues = json.as_array().unwrap();

    // P0 should be first
    assert_eq!(issues[0]["priority"], 0);
    assert_eq!(issues[1]["priority"], 1);
    assert_eq!(issues[2]["priority"], 3);
}

