#[test]
fn test_ready_json_output() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    create_issue(&beads_dir, "JSON test");

    let output = br_cmd(&beads_dir)
        .args(["ready", "--json"])
        .output()
        .unwrap();

    let json: Value = serde_json::from_slice(&output.stdout).unwrap();
    assert!(json.is_array());
    assert_eq!(json[0]["title"], "JSON test");
}

#[test]
fn test_ready_after_close_unblocks() {
    let (_, dir) = init_beads();
    let beads_dir = dir.path().join(".beads");

    let blocker = create_issue(&beads_dir, "Blocker");
    let blocked = create_issue(&beads_dir, "Will be ready");

    br_cmd(&beads_dir)
        .args(["dep", "add", &blocked, &blocker])
        .assert()
        .success();

    // Initially blocked is not ready
    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .stdout(predicate::str::contains("Will be ready").not());

    // Close blocker
    br_cmd(&beads_dir)
        .args(["close", &blocker])
        .assert()
        .success();

    // Now blocked should be ready
    br_cmd(&beads_dir)
        .arg("ready")
        .assert()
        .stdout(predicate::str::contains("Will be ready"));
}
